const refs=($('Query 引用資料').first().json.results)||[];
const corpus=refs.map((p,i)=>{const pr=p.properties||{};const nm=(pr['明細名稱']?.title||[]).map(t=>t.plain_text).join('');const sm=(pr['簡介摘要']?.rich_text||[]).map(t=>t.plain_text).join('');const ct=(pr['明細內容']?.rich_text||[]).map(t=>t.plain_text).join('');return (i+1)+'. '+nm+'
'+((sm||ct).slice(0,600));}).join('

');
const system='你是 makesense 嗨嗨家族的分析棒（認識/鑑定棒）。職責:逐筆讀引用資料,抽 5 類具名實體。
5 類:人物 / 地點 / 單位 / 事件 / 議題。
鐵律:全抽全建,不判斷值不值得;只抽資料裡真實出現的,不臆造;名稱要精確、可查證。
只回合法 JSON:{"items":[{"n":筆號,"entities":[{"type":"人物/地點/單位/事件/議題","name":"實體名稱"}]}]}';
const user='以下是 '+refs.length+' 筆引用資料,逐筆抽 5 類具名實體:

'+corpus+'

回 JSON。';
return [{json:{system,user,ref_count:refs.length}}];

const refs=($('Query 引用資料').first().json.results)||[];
const ce=$input.first().json;
const baton=$('Parse DB06').first().json;
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const DB08='873970187f394f6b8304406745bd1579';
let summary='', log=[], created=0, linked=0, total_ent=0, canon_ct=0;
try {
  const text=ce.content?.[0]?.text||'';
  let ext; try{const m=text.match(/\{[\s\S]*\}/);ext=JSON.parse(m[0]);}catch(e){ext={items:[]};}
  const items=ext.items||[];
  const refById=refs.map(p=>({id:p.id.replace(/-/g,''),name:(p.properties['明細名稱']?.title||[]).map(t=>t.plain_text).join('')}));
  // 正規化：去括號內容、去年份範圍、臺=台、去全半形空白
  const norm=(s)=>(s||'').toString().normalize('NFKC').replace(/[（(][^）)]*[）)]/g,'').replace(/[\s　]*\d{3,4}\s*[-－~～至]\s*\d{3,4}/g,'').replace(/臺/g,'台').replace(/[\s　]/g,'').trim();
  const entMap={};
  for(const it of items){for(const e of (it.entities||[])){const nm=(e.name||'').toString().trim();if(nm&&!entMap[nm])entMap[nm]=true;}}
  const uniq=Object.keys(entMap); total_ent=uniq.length;
  // 本批內部去重：正規化分組,canonical=組內第一個
  const groups={}, name2canon={};
  for(const nm of uniq){const k=norm(nm)||nm; if(!groups[k])groups[k]=nm; name2canon[nm]=groups[k];}
  const canon=Object.values(groups); canon_ct=canon.length;
  // load DB08
  let db08=[],cursor,guard=0;
  do{ const body={page_size:100}; if(cursor)body.start_cursor=cursor;
    const r=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/databases/'+DB08+'/query',headers:NHEAD,body:JSON.stringify(body)});
    const rr=(typeof r==='string')?JSON.parse(r):r;
    for(const p of (rr.results||[])) db08.push({id:p.id.replace(/-/g,''),title:(p.properties['對象名稱']?.title||[]).map(t=>t.plain_text).join('').trim(),syn:(p.properties['同義備註']?.rich_text||[]).map(t=>t.plain_text).join('')});
    cursor=rr.has_more?rr.next_cursor:null; guard++;
  }while(cursor&&guard<20);
  // DB08 正規化索引（title + 同義備註每行）
  const db08norm={};
  for(const d of db08){const keys=[d.title].concat(d.syn?d.syn.split('\n'):[]); for(const kk of keys){const nk=norm(kk); if(nk&&!(nk in db08norm))db08norm[nk]=d.id;}}
  // canonical → db08 id：先正規化命中
  const canon2id={}; const unmatched=[];
  for(const c of canon){const nk=norm(c); if(nk&&db08norm[nk])canon2id[c]=db08norm[nk]; else unmatched.push(c);}
  // Claude 語意查重（只查正規化未命中的）
  if(unmatched.length){
    const list=db08.map((d,i)=>i+'\t'+d.title+(d.syn?(' [別名:'+d.syn.replace(/\n/g,'/')+']'):'')).join('\n');
    const dsys='你做 DB08 實體查重。給你「抽出的實體」與「DB08 現有清單」。逐一判斷每個抽出實體在 DB08 是否已存在(語意同一,如 羅東=羅東鎮、旅人書店=Wanderer Books)。只回 JSON:{"map":[{"name":"實體名","idx":DB08編號或-1}]}。-1=不存在。';
    const dusr='抽出的實體:\n'+unmatched.join('\n')+'\n\nDB08 現有清單(編號 名稱):\n'+list+'\n\n回 JSON。';
    try{
      const cr=await this.helpers.httpRequest({method:'POST',url:'https://api.anthropic.com/v1/messages',headers:{'x-api-key':$env.ANTHROPIC_API_KEY,'anthropic-version':'2023-06-01','content-type':'application/json'},body:JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:4096,system:dsys,messages:[{role:'user',content:dusr}]})});
      const crr=(typeof cr==='string')?JSON.parse(cr):cr;
      const m=(crr.content?.[0]?.text||'').match(/\{[\s\S]*\}/);
      const dmap=m?(JSON.parse(m[0]).map||[]):[];
      for(const d of dmap){const i=parseInt(d.idx);if(i>=0&&db08[i])canon2id[d.name]=db08[i].id;}
    }catch(e){log.push('dedup fail');}
  }
  // create missing canonicals
  for(const c of canon){
    if(canon2id[c])continue;
    try{
      const cp=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/pages',headers:NHEAD,body:JSON.stringify({parent:{database_id:DB08},properties:{'對象名稱':{title:[{text:{content:c}}]},'經營類型':{select:{name:'紀錄'}}}})});
      const cpr=(typeof cp==='string')?JSON.parse(cp):cp;
      if(cpr.id){canon2id[c]=cpr.id.replace(/-/g,'');created++;}
    }catch(e){log.push('create fail '+c);}
  }
  // 每個實體名 → canonical 的 db08 id
  const name2id={};
  for(const nm of uniq){const c=name2canon[nm]; if(canon2id[c])name2id[nm]=canon2id[c];}
  // 3-token note
  const d=new Date(); const tw=new Date(d.getTime()+8*3600*1000);
  const note='資料參考｜'+tw.getUTCFullYear()+'/'+String(tw.getUTCMonth()+1).padStart(2,'0')+'/'+String(tw.getUTCDate()).padStart(2,'0')+'｜'+(baton.target_db||'DB06');
  for(const it of items){
    const ref=refById[(it.n||0)-1]; if(!ref)continue;
    const ids=[];
    for(const e of (it.entities||[])){const nm=(e.name||'').toString().trim();if(name2id[nm])ids.push(name2id[nm]);}
    const u=[...new Set(ids)];
    try{
      await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/pages/'+ref.id,headers:NHEAD,body:JSON.stringify({properties:{'對應標籤':{relation:u.map(id=>({id}))},'分析備註':{rich_text:[{text:{content:note}}]}}})});
      linked++;
    }catch(e){log.push('patch fail '+ref.id);}
  }
  summary='分析完成。處理 '+refById.length+' 筆引用資料,抽 '+total_ent+' 個具名實體(正規化去重後 '+canon_ct+' 個),新建 DB08 紀錄 '+created+' 筆,'+linked+' 筆已補對應標籤+分析備註。';
}catch(err){ summary='分析棒錯誤: '+(err&&err.message||err); }
const nowTW=new Date().toLocaleString('zh-TW',{timeZone:'Asia/Taipei'});
const exec_note='── '+nowTW+' 分析 ──\n'+summary+(log.length?('\n問題: '+log.slice(0,10).join('; ')):'');
return [{json:{db06_id:baton.db06_id,db05_id:baton.db05_id,ai_mode:baton.ai_mode,sort_num:baton.sort_num,exec_note,safe_summary:summary.slice(0,400),preview_text:summary.slice(0,300),validator_warning:'',usage_line:'分析棒 DB08 比對 新建'+created}}];

