const results = $input.first().json.results || [];
const g = $('Build gateB').first().json;
const total = results.length;
const done = results.filter(p=>(p.properties['ai狀態']?.status?.name||'')==='完成').length;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
if (pending.length === 0) {
  return [{ json: { has_next:false, tg_done:'🎉 全套完成 — 共 '+total+' 棒已全部跑完。' } }];
}
const p = pending[0];
const nid = p.id.replace(/-/g,'');
const nmode = p.properties['ai模式']?.select?.name || '';
const nidea = (p.properties['執行構想']?.rich_text||[]).map(t=>t.plain_text).join('').slice(0,600) || '(未填)';
const nsort = p.properties['排序']?.number;
const _b='https://makesense.zeabur.app/webhook/';
let runner_url;
if (nmode.includes('聯想')) runner_url=_b+'db06-lianxiang-traversal';
else if (nmode.includes('搜查')) runner_url=_b+'db06-search';
else if (nmode.includes('分析')) runner_url=_b+'db06-analyze';
else if (nmode.includes('文案')) runner_url=_b+'db06-copy';
else if (nmode.includes('檢核')) runner_url=_b+'db06-check';
else runner_url=_b+'db06-plan';
const gateA = '🛫 關卡A 執行前確認\n第 '+(nsort!=null?nsort:'?')+' 棒 ('+nmode+')。全套 '+total+' 棒,已完成 '+done+' 棒。\nDB06 '+nid+'\n\n本棒預定執行構想:\n'+nidea+'\n\n按 OK 放行這一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。\n📄 本棒頁面：https://www.notion.so/'+nid+'\ngateA db06='+nid;
return [{ json: { has_next:true, db06_id:nid, runner_url, gateA, cb_ok:'A1:'+nid, cb_all:'AA:'+nid } }];

const p=$input.first().json; const tp=p.properties||{};
let files=[];
for(const v of Object.values(tp)){ if(v&&v.type==='files'&&Array.isArray(v.files)){ files=files.concat(v.files); } }
let url='',name='';
for(const f of files){ const u=(f.file&&f.file.url)||(f.external&&f.external.url)||''; const nm=f.name||''; if(u&&/\.pdf(\?|$)/i.test(u+nm)){ url=u; name=nm||'document.pdf'; break; } }
return [{json:{has_pdf:!!url,pdf_url:url,pdf_name:name,target_id:(p.id||'').replace(/-/g,'')}}];

const cf=$input.first().json;
const pk=$('Pick PDF').first().json;
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const DB06='3469ff25fdab83c98ff98107ee6a6a1c';
let md='';
if(cf&&cf.success&&Array.isArray(cf.result)&&cf.result.length) md=cf.result[0].data||'';
let note='';
try{
  if(!md.trim()) throw new Error('Cloudflare 回傳空白');
  const mk=(t,c)=>{const o={object:'block',type:t};o[t]={rich_text:[{text:{content:(c||'').slice(0,1990)}}]};return o;};
  const blocks=[];
  for(let ln of md.split('\n')){
    if(!ln.trim()) continue;
    if(ln.startsWith('### ')) blocks.push(mk('heading_3',ln.slice(4)));
    else if(ln.startsWith('## ')) blocks.push(mk('heading_2',ln.slice(3)));
    else if(ln.startsWith('# ')) blocks.push(mk('heading_1',ln.slice(2)));
    else { for(let i=0;i<ln.length;i+=1900) blocks.push(mk('paragraph',ln.slice(i,i+1900))); }
  }
  const first=blocks.slice(0,100);
  const cp=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/pages',headers:NHEAD,body:JSON.stringify({
    parent:{database_id:DB06},
    properties:{'明細名稱':{title:[{text:{content:('📄 '+(pk.pdf_name||'PDF')).slice(0,200)}}]},'明細類型':{select:{name:'資料參考'}},'參考類別':{select:{name:'企劃參考'}}},
    children:first})});
  const cpr=(typeof cp==='string')?JSON.parse(cp):cp;
  const pid=(cpr.id||'').replace(/-/g,'');
  for(let i=100;i<blocks.length;i+=100){
    try{await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/blocks/'+pid+'/children',headers:NHEAD,body:JSON.stringify({children:blocks.slice(i,i+100)})});}catch(e){}
  }
  // link to target 明細引用
  const tp=await this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+pk.target_id,headers:NHEAD});
  const tpr=(typeof tp==='string')?JSON.parse(tp):tp;
  const ex=(((tpr.properties||{})['明細引用']||{}).relation||[]).map(x=>({id:x.id}));
  ex.push({id:pid});
  await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/pages/'+pk.target_id,headers:NHEAD,body:JSON.stringify({properties:{'明細引用':{relation:ex}}})});
  note='PDF '+(pk.pdf_name||'')+' 已轉文字('+md.length+' 字)、建成資料參考並連入 target 明細引用';
}catch(err){ note='PDF 處理失敗：'+(err&&err.message||err); }
return [{json:{pdf_note:note}}];
